def load_certificate():
    """Load the IdP's X.509 certificate."""
    cert_path = IDP_CONFIG["certificate_file"]
    if os.path.exists(cert_path):
        with open(cert_path, "r") as f:
            return f.read()
    else:
        raise FileNotFoundError(
            f"Certificate file not found: {cert_path}. "
            "Generate with: openssl req -x509 -newkey rsa:2048 -keyout idp_key.pem "
            "-out idp_cert.pem -days 365 -nodes -subj '/CN=idp.internal.example.com'"
        )


def load_private_key():
    """Load the IdP's private key."""
    key_path = IDP_CONFIG["private_key_file"]
    if os.path.exists(key_path):
        with open(key_path, "r") as f:
            return f.read()
    else:
        raise FileNotFoundError(f"Private key file not found: {key_path}")


def get_certificate_clean():
    """Get certificate content without PEM headers."""
    cert = load_certificate()
    cert = cert.replace("-----BEGIN CERTIFICATE-----", "")
    cert = cert.replace("-----END CERTIFICATE-----", "")
    cert = cert.replace("\n", "").replace("\r", "").strip()
    return cert


def authenticate_user(username, password):
    """
    Authenticate user against the internal user store.
    In production, replace with LDAP/Active Directory authentication.
    """
    user = USER_STORE.get(username)
    if user and user["password"] == password:  # Use bcrypt/argon2 in production
        return user
    return None


def parse_saml_request(encoded_request, is_redirect=False):
    """Parse and decode an incoming SAML AuthnRequest."""
    try:
        decoded = base64.b64decode(encoded_request)
        if is_redirect:
            import zlib
            decoded = zlib.decompress(decoded, -15)
        root = etree.fromstring(decoded)
        request_data = {
            "id": root.get("ID"),
            "issuer": None,
            "acs_url": root.get("AssertionConsumerServiceURL"),
            "destination": root.get("Destination"),
            "protocol_binding": root.get("ProtocolBinding"),
        }
        issuer_elem = root.find("{urn:oasis:names:tc:SAML:2.0:assertion}Issuer")
        if issuer_elem is not None:
            request_data["issuer"] = issuer_elem.text
        return request_data
    except Exception as e:
        app.logger.error(f"Failed to parse SAML request: {e}")
        return None


def generate_response_id():
    """Generate a unique ID for SAML response/assertion."""
    return "_" + uuid.uuid4().hex


def build_saml_response(user, request_data, sp_config):
    """
    Build a SAML Response XML document with a signed assertion.
    Assertions are signed but NOT encrypted - HTTPS provides transport security.
    """
    now = datetime.now(timezone.utc)
    not_before = now - timedelta(minutes=5)  # Clock skew allowance
    not_on_or_after = now + timedelta(minutes=IDP_CONFIG["session_duration_minutes"])
    session_not_on_or_after = now + timedelta(minutes=IDP_CONFIG["session_duration_minutes"])
    issue_instant = now.strftime("%Y-%m-%dT%H:%M:%SZ")
    not_before_str = not_before.strftime("%Y-%m-%dT%H:%M:%SZ")
    not_on_or_after_str = not_on_or_after.strftime("%Y-%m-%dT%H:%M:%SZ")
    session_not_on_or_after_str = session_not_on_or_after.strftime("%Y-%m-%dT%H:%M:%SZ")

    response_id = generate_response_id()
    assertion_id = generate_response_id()
    session_index = generate_response_id()

    in_response_to = request_data.get("id", "")
    acs_url = sp_config["acs_url"]
    sp_entity_id = sp_config["entity_id"]
    idp_entity_id = IDP_CONFIG["entity_id"]

    # Build the SAML Response XML
    nsmap = {
        "samlp": SAML_NAMESPACES["samlp"],
        "saml": SAML_NAMESPACES["saml"],
    }

    response = etree.Element(
        "{%s}Response" % SAML_NAMESPACES["samlp"],
        nsmap=nsmap,
    )
    response.set("ID", response_id)
    response.set("Version", "2.0")
    response.set("IssueInstant", issue_instant)
    response.set("Destination", acs_url)
    if in_response_to:
        response.set("InResponseTo", in_response_to)

    # Response Issuer
    response_issuer = etree.SubElement(response, "{%s}Issuer" % SAML_NAMESPACES["saml"])
    response_issuer.text = idp_entity_id

    # Status
    status = etree.SubElement(response, "{%s}Status" % SAML_NAMESPACES["samlp"])
    status_code = etree.SubElement(status, "{%s}StatusCode" % SAML_NAMESPACES["samlp"])
    status_code.set("Value", "urn:oasis:names:tc:SAML:2.0:status:Success")

    # Assertion
    assertion = etree.SubElement(response, "{%s}Assertion" % SAML_NAMESPACES["saml"])
    assertion.set("xmlns:saml", SAML_NAMESPACES["saml"])
    assertion.set("ID", assertion_id)
    assertion.set("Version", "2.0")
    assertion.set("IssueInstant", issue_instant)

    # Assertion Issuer
    assertion_issuer = etree.SubElement(assertion, "{%s}Issuer" % SAML_NAMESPACES["saml"])
    assertion_issuer.text = idp_entity_id

    # Subject
    subject = etree.SubElement(assertion, "{%s}Subject" % SAML_NAMESPACES["saml"])
    name_id = etree.SubElement(subject, "{%s}NameID" % SAML_NAMESPACES["saml"])
    name_id.set("Format", IDP_CONFIG["name_id_format"])
    name_id.set("SPNameQualifier", sp_entity_id)
    name_id.text = user["email"]

    subject_confirmation = etree.SubElement(
        subject, "{%s}SubjectConfirmation" % SAML_NAMESPACES["saml"]
    )
    subject_confirmation.set("Method", "urn:oasis:names:tc:SAML:2.0:cm:bearer")
    subject_confirmation_data = etree.SubElement(
        subject_confirmation, "{%s}SubjectConfirmationData" % SAML_NAMESPACES["saml"]
    )
    if in_response_to:
        subject_confirmation_data.set("InResponseTo", in_response_to)
    subject_confirmation_data.set("NotOnOrAfter", not_on_or_after_str)
    subject_confirmation_data.set("Recipient", acs_url)

    # Conditions
    conditions = etree.SubElement(assertion, "{%s}Conditions" % SAML_NAMESPACES["saml"])
    conditions.set("NotBefore", not_before_str)
    conditions.set("NotOnOrAfter", not_on_or_after_str)
    audience_restriction = etree.SubElement(
        conditions, "{%s}AudienceRestriction" % SAML_NAMESPACES["saml"]
    )
    audience = etree.SubElement(audience_restriction, "{%s}Audience" % SAML_NAMESPACES["saml"])
    audience.text = sp_entity_id

    # AuthnStatement
    authn_statement = etree.SubElement(
        assertion, "{%s}AuthnStatement" % SAML_NAMESPACES["saml"]
    )
    authn_statement.set("AuthnInstant", issue_instant)
    authn_statement.set("SessionIndex", session_index)
    authn_statement.set("SessionNotOnOrAfter", session_not_on_or_after_str)
    authn_context = etree.SubElement(
        authn_statement, "{%s}AuthnContext" % SAML_NAMESPACES["saml"]
    )
    authn_context_class_ref = etree.SubElement(
        authn_context, "{%s}AuthnContextClassRef" % SAML_NAMESPACES["saml"]
    )
    authn_context_class_ref.text = (
        "urn:oasis:names:tc:SAML:2.0:ac:classes:PasswordProtectedTransport"
    )

    # AttributeStatement
    attribute_statement = etree.SubElement(
        assertion, "{%s}AttributeStatement" % SAML_NAMESPACES["saml"]
    )

    # Add user attributes
    attributes = {
        "email": user["email"],
        "firstName": user["first_name"],
        "lastName": user["last_name"],
        "department": user.get("department", ""),
    }

    for attr_name, attr_value in attributes.items():
        attribute = etree.SubElement(
            attribute_statement, "{%s}Attribute" % SAML_NAMESPACES["saml"]
        )
        attribute.set("Name", attr_name)
        attribute.set("NameFormat", "urn:oasis:names:tc:SAML:2.0:attrname-format:basic")
        attr_val = etree.SubElement(
            attribute, "{%s}AttributeValue" % SAML_NAMESPACES["saml"]
        )
        attr_val.set(
            "{%s}type" % SAML_NAMESPACES["xsi"],
            "xs:string",
        )
        attr_val.text = attr_value

    # Add roles as multi-valued attribute
    roles_attribute = etree.SubElement(
        attribute_statement, "{%s}Attribute" % SAML_NAMESPACES["saml"]
    )
    roles_attribute.set("Name", "roles")
    roles_attribute.set("NameFormat", "urn:oasis:names:tc:SAML:2.0:attrname-format:basic")
    for role in user.get("roles", []):
        role_val = etree.SubElement(
            roles_attribute, "{%s}AttributeValue" % SAML_NAMESPACES["saml"]
        )
        role_val.set(
            "{%s}type" % SAML_NAMESPACES["xsi"],
            "xs:string",
        )
        role_val.text = role

    return response, assertion


def sign_assertion(response_xml, assertion_element):
    """
    Sign the SAML assertion using XML Digital Signature (xmldsig).
    Uses RSA-SHA256 for signing and SHA256 for digest.
    The signature is placed inside the assertion, after the Issuer element.
    """
    private_key_pem = load_private_key()
    certificate_pem = load_certificate()

    # Create signature template
    signature_node = xmlsec.template.create(
        assertion_element,
        c14n_method=xmlsec.constants.TransformExclC14N,
        sign_method=xmlsec.constants.TransformRsaSha256,
        ns="ds",
    )

    # Add reference to the assertion
    ref = xmlsec.template.add_reference(
        signature_node,
        digest_method=xmlsec.constants.TransformSha256,
        uri="#" + assertion_element.get("ID"),
    )
    xmlsec.template.add_transform(ref, xmlsec.constants.TransformEnveloped)
    xmlsec.template.add_transform(ref, xmlsec.constants.TransformExclC14N)

    # Add KeyInfo with X509 certificate
    key_info = xmlsec.template.ensure_key_info(signature_node)
    x509_data = xmlsec.template.add_x509_data(key_info)
    xmlsec.template.x509_data_add_certificate(x509_data)

    # Insert signature after Issuer element in the assertion
    issuer = assertion_element.find("{%s}Issuer" % SAML_NAMESPACES["saml"])
    if issuer is not None:
        issuer.addnext(signature_node)
    else:
        assertion_element.insert(0, signature_node)

    # Perform the signing
    ctx = xmlsec.SignatureContext()

    # Load private key
    key = xmlsec.Key.from_memory(private_key_pem, xmlsec.constants.KeyDataFormatPem)
    key.load_cert(certificate_pem, xmlsec.constants.KeyDataFormatPem)
    ctx.key = key

    # Sign
    ctx.sign(signature_node)

    return response_xml


def encode_saml_response(response_xml):
    """Encode the SAML response as base64 for POST binding."""
    xml_string = etree.tostring(response_xml, xml_declaration=True, encoding="UTF-8")
    return base64.b64encode(xml_string).decode("utf-8")


@app.route("/sso", methods=["GET", "POST"])
def single_sign_on():
    """
    Single Sign-On endpoint.
    Handles both GET (redirect binding) and POST (post binding) for AuthnRequests.
    """
    saml_request = None
    relay_state = ""
    is_redirect = False

    if request.method == "GET":
        saml_request = request.args.get("SAMLRequest")
        relay_state = request.args.get("RelayState", "")
        is_redirect = True
    else:
        # POST can be either an AuthnRequest submission or a login form submission
        saml_request = request.form.get("SAMLRequest")
        relay_state = request.form.get("RelayState", "")

    if not saml_request:
        return "Missing SAMLRequest parameter", 400

    # Check if this is a login form submission (has username/password)
    username = request.form.get("username")
    password = request.form.get("password")

    if username and password:
        # Process login
        return process_login(username, password, saml_request, relay_state)

    # Parse the SAML request to get SP info
    request_data = parse_saml_request(saml_request, is_redirect=is_redirect)
    if not request_data:
        return "Invalid SAMLRequest", 400

    # Validate the SP
    sp_entity_id = request_data.get("issuer")
    if sp_entity_id not in SP_REGISTRY:
        app.logger.warning(f"Unknown SP attempted SSO: {sp_entity_id}")
        return "Unknown Service Provider", 403

    sp_config = SP_REGISTRY[sp_entity_id]

    # Check if user already has an active session
    if "user_email" in session:
        user = USER_STORE.get(session["user_email"])
        if user:
            return generate_and_send_response(user, request_data, sp_config, relay_state)

    # Re-encode for redirect binding requests (they were decompressed)
    if is_redirect:
        saml_request_b64 = request.args.get("SAMLRequest", "")
    else:
        saml_request_b64 = saml_request

    # Show login form
    return render_template_string(
        LOGIN_TEMPLATE,
        saml_request=saml_request_b64,
        relay_state=relay_state,
        sp_name=sp_config.get("name", "Unknown Application"),
        error=None,
    )


def process_login(username, password, saml_request, relay_state):
    """Process login credentials and generate SAML response if valid."""
    user = authenticate_user(username, password)

    if not user:
        # Determine if this was originally a redirect binding request
        request_data = parse_saml_request(saml_request, is_redirect=False)
        if not request_data:
            request_data = parse_saml_request(saml_request, is_redirect=True)

        sp_name = "Unknown Application"
        if request_data and request_data.get("issuer") in SP_REGISTRY:
            sp_name = SP_REGISTRY[request_data["issuer"]].get("name", sp_name)

        return render_template_string(
            LOGIN_TEMPLATE,
            saml_request=saml_request,
            relay_state=relay_state,
            sp_name=sp_name,
            error="Invalid username or password",
        )

    # Try parsing as POST binding first, then redirect binding
    request_data = parse_saml_request(saml_request, is_redirect=False)
    if not request_data:
        request_data = parse_saml_request(saml_request, is_redirect=True)

    if not request_data:
        return "Invalid SAMLRequest", 400

    sp_entity_id = request_data.get("issuer")
    if sp_entity_id not in SP_REGISTRY:
        return "Unknown Service Provider", 403

    sp_config = SP_REGISTRY[sp_entity_id]

    # Create session
    session["user_email"] = user["email"]
    session["auth_time"] = datetime.now(timezone.utc).isoformat()

    return generate_and_send_response(user, request_data, sp_config, relay_state)


def generate_and_send_response(user, request_data, sp_config, relay_state):
    """Generate a signed SAML response and send it to the SP via POST binding."""
    # Build the SAML response
    response_xml, assertion_element = build_saml_response(user, request_data, sp_config)

    # Sign the assertion (not encrypted - HTTPS provides transport security)
    signed_response = sign_assertion(response_xml, assertion_element)

    # Encode for POST binding
    encoded_response = encode_saml_response(signed_response)

    app.logger.info(
        f"SAML response generated for user={user['email']} "
        f"sp={sp_config['entity_id']} "
        f"in_response_to={request_data.get('id', 'N/A')}"
    )

    # Send via POST binding (auto-submitting form)
    return render_template_string(
        POST_BINDING_TEMPLATE,
        acs_url=sp_config["acs_url"],
        saml_response=encoded_response,
        relay_state=relay_state,
    )


@app.route("/slo", methods=["GET", "POST"])
def single_logout():
    """Single Logout endpoint."""
    session.clear()

    relay_state = request.args.get("RelayState") or request.form.get("RelayState", "")
    if relay_state:
        return redirect(relay_state)

    return """
    <!DOCTYPE html>
    <html>
    <head><title>Logged Out</title></head>
    <body style="font-family: Arial; text-align: center; padding-top: 100px;">
        <h2>You have been logged out</h2>
        <p>Your session has been terminated.</p>
    </body>
    </html>
    """


