@app.route("/register-sp", methods=["POST"])
def register_sp():
    """
    Register a new Service Provider (admin endpoint).
    In production, this should be protected with admin authentication.
    """
    data = request.get_json()
    if not data:
        return {"error": "JSON body required"}, 400

    required_fields = ["entity_id", "acs_url", "name"]
    for field in required_fields:
        if field not in data:
            return {"error": f"Missing required field: {field}"}, 400

    SP_REGISTRY[data["entity_id"]] = {
        "entity_id": data["entity_id"],
        "acs_url": data["acs_url"],
        "name": data["name"],
    }

    app.logger.info(f"Registered new SP: {data['entity_id']}")
    return {"message": "Service Provider registered successfully"}, 201


@app.route("/health", methods=["GET"])
def health_check():
    """Health check endpoint."""
    try:
        load_certificate()
        load_private_key()
        cert_ok = True
    except FileNotFoundError:
        cert_ok = False

    return {
        "status": "healthy" if cert_ok else "degraded",
        "certificates_loaded": cert_ok,
        "registered_sps": len(SP_REGISTRY),
        "timestamp": datetime.now(timezone.utc).isoformat(),
    }


def generate_self_signed_cert():
    """
    Generate self-signed certificate and private key for development.
    In production, use certificates from your internal CA.
    """
    from cryptography import x509
    from cryptography.x509.oid import NameOID
    from cryptography.hazmat.primitives import hashes, serialization
    from cryptography.hazmat.primitives.asymmetric import rsa

    key = rsa.generate_private_key(public_exponent=65537, key_size=2048)

    subject = issuer = x509.Name([
        x509.NameAttribute(NameOID.COMMON_NAME, "idp.internal.example.com"),
        x509.NameAttribute(NameOID.ORGANIZATION_NAME, "Internal"),
    ])

    cert = (
        x509.CertificateBuilder()
        .subject_name(subject)
        .issuer_name(issuer)
        .public_key(key.public_key())
        .serial_number(x509.random_serial_number())
        .not_valid_before(datetime.now(timezone.utc))
        .not_valid_after(datetime.now(timezone.utc) + timedelta(days=365))
        .sign(key, hashes.SHA256())
    )

    with open(IDP_CONFIG["private_key_file"], "wb") as f:
        f.write(key.private_bytes(
            encoding=serialization.Encoding.PEM,
            format=serialization.PrivateFormat.TraditionalOpenSSL,
            encryption_algorithm=serialization.NoEncryption(),
        ))

    with open(IDP_CONFIG["certificate_file"], "wb") as f:
        f.write(cert.public_bytes(serialization.Encoding.PEM))

    print("Generated self-signed certificate and private key for development.")


if __name__ == "__main__":
    import sys

    # Generate certificates if they don't exist
    if not os.path.exists(IDP_CONFIG["certificate_file"]) or not os.path.exists(
        IDP_CONFIG["private_key_file"]
    ):
        print("Certificate files not found. Generating self-signed certificates...")
        try:
            generate_self_signed_cert()
        except ImportError:
            print(
                "Install 'cryptography' package to auto-generate certificates, "
                "or provide your own certificate files."
            )
            sys.exit(1)

    # Run with HTTPS in development
    # In production, use a proper WSGI server (gunicorn) behind a reverse proxy with TLS
    ssl_context = (IDP_CONFIG["certificate_file"], IDP_CONFIG["private_key_file"])

    print("=" * 60)
    print("Internal SAML Identity Provider")
    print("=" * 60)
    print(f"Entity ID:    {IDP_CONFIG['entity_id']}")
    print(f"SSO URL:      {IDP_CONFIG['sso_url']}")
    print(f"SLO URL:      {IDP_CONFIG['slo_url']}")
    print(f"Metadata URL: {IDP_CONFIG['entity_id'].replace('/metadata', '')}/metadata")
    print(f"Registered SPs: {len(SP_REGISTRY)}")
    print()
    print("NOTE: Assertions are signed but NOT encrypted.")
    print("HTTPS provides transport-layer security for assertion confidentiality.")
    print("=" * 60)

    app.run(
        host="0.0.0.0",
        port=8443,
        ssl_context=ssl_context,
        debug=False,
    )